static inline void predict_int8(const float* input, float* output) {
    float a[64], b[64];
    float logits[64];
    const float* in = input;
    float* out = a;

    // layer 1 (relu) - INT8 SYMMETRIC QUANTIZED
    for (int i = 0; i < 64; i++) {
        float sum = b1[i];
        for (int j = 0; j < 784; j++) {
            // Symmetric dequantization: q * scale (no zero point)
            float w_float = (float)w1[i][j] * w1_scales[i];
            sum += w_float * in[j];
        }
        out[i] = relu(sum);
    }
    in = out; out = (out == a) ? b : a;

    // layer 2 (softmax) - INT8 SYMMETRIC QUANTIZED
    for (int i = 0; i < 10; i++) {
        float sum = b2[i];
        for (int j = 0; j < 64; j++) {
            float w_float = (float)w2[i][j] * w2_scales[i];
            sum += w_float * in[j];
        }
        logits[i] = sum;
    }
    float max_logit = logits[0];
    for (int i = 1; i < 10; i++) {
        if (logits[i] > max_logit)
            max_logit = logits[i];
    }
    float exp_sum = 0.0f;
    for (int i = 0; i < 10; i++) {
        out[i] = expf(logits[i] - max_logit);
        exp_sum += out[i];
    }
    for (int i = 0; i < 10; i++) {
        out[i] /= exp_sum;
    }

    for (int i = 0; i < 10; i++)
        output[i] = out[i];
}

// Wrapper: predict() delegates to predict_int8()
static inline void predict(const float* input, float* output) {
    predict_int8(input, output);
}

